      <rect x="28" y="103" width="120" height="12" rx="4" fill={palette.mid} opacity="0.10" />
      {/* Accent highlight on first row */}
      <rect x="28" y="52" width="5" height="12" rx="2" fill={palette.accent} />
    </svg>
  );
}
